n, m = map(int, input().split())
edges = [list(map(int, input().split())) for _ in range(m)]

# find the edge with the highest indegree
max_indegree = 0
max_indegree_edge = None
for i in range(1, n+1):
    indegree = 0
    for j in range(m):
        if edges[j][1] == i:
            indegree += 1
    if indegree > max_indegree:
        max_indegree = indegree
        max_indegree_edge = (i, max_indegree)

# if the highest indegree is greater than 1, it is impossible to make the graph acyclic
if max_indegree > 1:
    print("NO")
    exit()

# if the highest indegree is 1, remove the edge with the highest indegree and check if the graph is acyclic
for i in range(m):
    if edges[i][1] == max_indegree_edge[0]:
        edges.pop(i)
        break

# check if the graph is acyclic
visited = [False] * (n+1)
def dfs(v):
    visited[v] = True
    for i in range(m):
        if edges[i][0] == v:
            if visited[edges[i][1]]:
                return False
            if not dfs(edges[i][1]):
                return False
    return True

if dfs(max_indegree_edge[0]):
    print("YES")
else:
    print("NO")

